class KaynakSayaci:
    def __init__(self):
        self.aktif = False

    def __enter__(self):
        # kaynağı aç ve nesneyi döndür
        pass

    def __exit__(self, exc_type, exc, tb):
        # kaynağı kapat; hatayı bastırma
        pass


def kaynak_durumu():
    kaynak = KaynakSayaci()
    with kaynak as aktif_kaynak:
        blok_ici = aktif_kaynak.aktif
    return [blok_ici, kaynak.aktif]


print(kaynak_durumu())

from contextlib import contextmanager


@contextmanager
def gecici_ayar(ayarlar, anahtar, yeni_deger):
    # eski değeri sakla, yeni değeri uygula ve finally içinde geri yükle
    pass


def ayar_akisi():
    ayarlar = {"mod": "production"}
    with gecici_ayar(ayarlar, "mod", "test"):
        blok_ici = ayarlar["mod"]
    return [blok_ici, ayarlar["mod"]]


print(ayar_akisi())

